## Task 7 — tool: search_term

**목표:** `search_term` tool이 TbStdWord + TbStdDomain + TbTrmForbiddenWord를 쿼리하여 결과를 반환한다.

### 입력/출력 스키마

```typescript
// 입력
{
  query: string          // 검색어 (한글/영문/약어)
  type?: 'all' | 'word' | 'domain' | 'term' | 'forbidden'  // 기본 'all'
  limit?: number         // 기본 10, 최대 50
}
// 출력
{
  results: Array<{
    type: 'word' | 'domain' | 'term' | 'forbidden'
    id: number
    name: string         // 한글명
    engName?: string     // 영문명
    abbr?: string        // 약어
  }>
  total: number
}
```

### 생성 파일

**`features/mcp/tools/search-term.ts`**

```typescript
import { z } from 'zod'
import { prisma } from '@/lib/prisma'

const inputSchema = z.object({
  query: z.string().min(1),
  type: z.enum(['all', 'word', 'domain', 'term', 'forbidden']).default('all'),
  limit: z.number().int().min(1).max(50).default(10),
})

export type SearchTermInput = z.infer<typeof inputSchema>

export async function searchTerm(rawInput: unknown) {
  const { query, type, limit } = inputSchema.parse(rawInput)
  const results: Array<{ type: string; id: number; name: string; engName?: string; abbr?: string }> = []

  if (type === 'all' || type === 'word') {
    const words = await prisma.word.findMany({
      where: {
        OR: [
          { wordKor: { contains: query, mode: 'insensitive' } },
          { wordEng: { contains: query, mode: 'insensitive' } },
          { wordAbbr: { contains: query, mode: 'insensitive' } },
        ],
      },
      take: limit,
    })
    results.push(...words.map((w) => ({
      type: 'word' as const, id: w.id, name: w.wordKor, engName: w.wordEng, abbr: w.wordAbbr ?? undefined,
    })))
  }

  if (type === 'all' || type === 'domain') {
    const domains = await prisma.domain.findMany({
      where: {
        OR: [
          { name: { contains: query, mode: 'insensitive' } },
          { code: { contains: query, mode: 'insensitive' } },
        ],
      },
      take: limit,
    })
    results.push(...domains.map((d) => ({
      type: 'domain' as const, id: d.id, name: d.name, abbr: d.code,
    })))
  }

  if (type === 'all' || type === 'forbidden') {
    const forbidden = await prisma.forbiddenWord.findMany({
      where: { wordKor: { contains: query, mode: 'insensitive' } },
      take: limit,
    })
    results.push(...forbidden.map((f) => ({
      type: 'forbidden' as const, id: f.id, name: f.wordKor,
    })))
  }

  return { results: results.slice(0, limit), total: results.length }
}

export const searchTermSchema = inputSchema
```

