### 9.2 `suggest_naming`

**`features/mcp/tools/suggest-naming.ts`**

```typescript
import { z } from 'zod'
import { prisma } from '@/lib/prisma'

const inputSchema = z.object({
  koreanDescription: z.string().min(1),
  target: z.enum(['db_column', 'java_field', 'both']).default('both'),
})

export async function suggestNaming(rawInput: unknown) {
  const { koreanDescription, target } = inputSchema.parse(rawInput)

  // 단순 전략: 한글 설명에서 공백 분리 후 각 단어를 TbStdWord 한글명 검색
  const korTokens = koreanDescription.split(/\s+/).filter(Boolean)

  const matchedAbbrs: string[] = []
  const basedOn: string[] = []

  for (const kor of korTokens) {
    const word = await prisma.word.findFirst({
      where: { wordKor: { contains: kor, mode: 'insensitive' } },
      orderBy: { wordKor: 'asc' },
    })
    if (word?.wordAbbr) {
      matchedAbbrs.push(word.wordAbbr.toUpperCase())
      basedOn.push(`${kor} → ${word.wordAbbr}`)
    } else if (word) {
      matchedAbbrs.push(word.wordEng.toUpperCase())
      basedOn.push(`${kor} → ${word.wordEng}`)
    }
  }

  const confidence: 'high' | 'medium' | 'low' =
    matchedAbbrs.length === korTokens.length ? 'high'
    : matchedAbbrs.length > 0 ? 'medium'
    : 'low'

  const dbColumn = (target === 'db_column' || target === 'both') && matchedAbbrs.length > 0
    ? matchedAbbrs.join('_')
    : undefined
  const javaField = (target === 'java_field' || target === 'both') && matchedAbbrs.length > 0
    ? matchedAbbrs[0].toLowerCase() + matchedAbbrs.slice(1).map((a) => a[0].toUpperCase() + a.slice(1).toLowerCase()).join('')
    : undefined

  return { dbColumn, javaField, confidence, basedOn }
}

export const suggestNamingSchema = inputSchema
```

테스트 파일: **`features/mcp/tools/__tests__/suggest-naming.test.ts`** (4건)
