import { createHash } from 'crypto'
import { prisma } from '@/lib/prisma'
import { MCP_ERROR } from './errors'
import type { AuthResult } from './errors'

export async function verifyPat(authHeader: string | null): Promise<AuthResult> {
  if (!authHeader?.startsWith('Bearer trmdict_pat_')) {
    return { ok: false, errorCode: MCP_ERROR.AUTH_REQUIRED, message: 'Authentication required' }
  }
  const token = authHeader.slice('Bearer '.length)
  const tokenHash = createHash('sha256').update(token).digest('hex')

  const record = await prisma.tbTrmMcpToken.findUnique({ where: { tokenHash } })
  if (!record) {
    return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Invalid token' }
  }
  if (record.revokedAt) {
    return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Token has been revoked' }
  }
  if (record.expiresAt && record.expiresAt < new Date()) {
    return { ok: false, errorCode: MCP_ERROR.INVALID_TOKEN, message: 'Token has expired' }
  }

  // Resolve role via Supabase Admin API
  const { createClient } = await import('@supabase/supabase-js')
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!,
  )
  const { data } = await supabase.auth.admin.getUserById(record.userId)
  const role: 'USER' | 'ADMIN' =
    data?.user?.app_metadata?.role === 'ADMIN' ? 'ADMIN' : 'USER'

  // fire-and-forget last_used_at update
  prisma.tbTrmMcpToken
    .update({ where: { id: record.id }, data: { lastUsedAt: new Date() } })
    .catch(() => {})

  return { ok: true, tokenId: record.id, userId: record.userId, role }
}

