import { prisma } from '@/lib/prisma'
import { MCP_ERROR } from './errors'

const LIMITS: Record<'USER' | 'ADMIN', number> = { USER: 60, ADMIN: 200 }

export type RateLimitResult =
  | { ok: true }
  | { ok: false; errorCode: typeof MCP_ERROR.RATE_LIMIT; retryAfter: number }

function windowKey(): string {
  const now = new Date()
  const pad = (n: number) => String(n).padStart(2, '0')
  return (
    `${now.getUTCFullYear()}-${pad(now.getUTCMonth() + 1)}-${pad(now.getUTCDate())}` +
    `T${pad(now.getUTCHours())}:${pad(now.getUTCMinutes())}`
  )
}

export async function checkRateLimit(
  tokenId: bigint,
  role: 'USER' | 'ADMIN',
): Promise<RateLimitResult> {
  const limit = LIMITS[role]
  const key = windowKey()

  // atomic upsert: insert with count=1 or increment existing
  await prisma.$executeRaw`
    INSERT INTO tb_trm_mcp_rate_limit (token_id, window_key, count)
    VALUES (${tokenId}, ${key}, 1)
    ON CONFLICT (token_id, window_key)
    DO UPDATE SET count = tb_trm_mcp_rate_limit.count + 1
  `

  const record = await prisma.tbTrmMcpRateLimit.findUnique({
    where: { tokenId_windowKey: { tokenId, windowKey: key } },
  })
  const count = record?.count ?? 1

  if (count > limit) {
    const now = new Date()
    const retryAfter = 60 - now.getUTCSeconds()
    return { ok: false, errorCode: MCP_ERROR.RATE_LIMIT, retryAfter }
  }
  return { ok: true }
}

