import { z } from 'zod'
import { prisma } from '@/lib/prisma'

export const checkForbiddenSchema = z.object({
  text: z.string().min(1, 'text must not be empty'),
})

export async function checkForbiddenInText(rawInput: unknown) {
  const { text } = checkForbiddenSchema.parse(rawInput)
  const forbidden = await prisma.forbiddenWord.findMany({
    select: { id: true, wordKor: true, reason: true },
  })

  const matches: Array<{ word: string; position: number; reason: string | null }> = []
  for (const f of forbidden) {
    const idx = text.indexOf(f.wordKor)
    if (idx !== -1) {
      matches.push({ word: f.wordKor, position: idx, reason: f.reason })
    }
  }
  return { hasForbidden: matches.length > 0, matches }
}

