import { z } from 'zod'
import { prisma } from '@/lib/prisma'

export const validateIdentifierSchema = z.object({
  name: z.string().min(1, 'name must not be empty'),
  kind: z.enum(['db_column', 'db_table', 'java_class', 'java_field', 'java_method']),
})

function tokenize(name: string, kind: string): string[] {
  if (kind === 'db_column' || kind === 'db_table') {
    return name.toUpperCase().split('_').filter(Boolean)
  }
  // camelCase / PascalCase → split at uppercase boundaries
  return name
    .replace(/([A-Z])/g, ' $1')
    .trim()
    .split(/\s+/)
    .map((t) => t.toUpperCase())
    .filter(Boolean)
}

export async function validateIdentifier(rawInput: unknown) {
  const { name, kind } = validateIdentifierSchema.parse(rawInput)
  const tokens = tokenize(name, kind)

  const tokenResults: Array<{ token: string; source: 'standard' | 'custom' | 'unknown' }> = []

  for (const token of tokens) {
    const std = await prisma.word.findFirst({
      where: { wordAbbr: { equals: token, mode: 'insensitive' } },
    })
    if (std) {
      tokenResults.push({ token, source: 'standard' })
      continue
    }
    const custom = await prisma.tbTrmCustomWord.findFirst({
      where: {
        wordEngAbbrNm: { equals: token, mode: 'insensitive' },
        useYn: 'Y',
      },
    })
    tokenResults.push({ token, source: custom ? 'custom' : 'unknown' })
  }

  const invalidTokens = tokenResults
    .filter((t) => t.source === 'unknown')
    .map((t) => t.token)
  const valid = invalidTokens.length === 0
  const suggestionMessage = valid
    ? undefined
    : `비표준 토큰 [${invalidTokens.join(', ')}]이 포함되어 있습니다. register_custom_word 또는 propose_term으로 등록을 요청하세요.`

  return { valid, tokens: tokenResults, invalidTokens, suggestionMessage }
}

