import { z } from 'zod'
import { prisma } from '@/lib/prisma'

export const suggestNamingSchema = z.object({
  koreanDescription: z.string().min(1, 'koreanDescription must not be empty'),
  target: z.enum(['db_column', 'java_field', 'both']).default('both'),
})

export async function suggestNaming(rawInput: unknown) {
  const { koreanDescription, target } = suggestNamingSchema.parse(rawInput)

  const korTokens = koreanDescription.split(/\s+/).filter(Boolean)
  const matchedAbbrs: string[] = []
  const basedOn: string[] = []

  for (const kor of korTokens) {
    const word = await prisma.word.findFirst({
      where: { wordKor: { contains: kor, mode: 'insensitive' } },
      orderBy: { wordKor: 'asc' },
    })
    if (word?.wordAbbr) {
      matchedAbbrs.push(word.wordAbbr.toUpperCase())
      basedOn.push(`${kor} → ${word.wordAbbr}`)
    } else if (word) {
      matchedAbbrs.push(word.wordEng.toUpperCase())
      basedOn.push(`${kor} → ${word.wordEng}`)
    }
  }

  const confidence: 'high' | 'medium' | 'low' =
    matchedAbbrs.length === korTokens.length
      ? 'high'
      : matchedAbbrs.length > 0
        ? 'medium'
        : 'low'

  const dbColumn =
    (target === 'db_column' || target === 'both') && matchedAbbrs.length > 0
      ? matchedAbbrs.join('_')
      : undefined

  const javaField =
    (target === 'java_field' || target === 'both') && matchedAbbrs.length > 0
      ? matchedAbbrs[0].toLowerCase() +
        matchedAbbrs
          .slice(1)
          .map((a) => a[0].toUpperCase() + a.slice(1).toLowerCase())
          .join('')
      : undefined

  return { dbColumn, javaField, confidence, basedOn }
}

