export const runtime = 'nodejs'
export const dynamic = 'force-dynamic'

export async function POST(req: NextRequest) {
  const start = Date.now()

  // 1. Authentication
  const authResult = await verifyPat(req.headers.get('authorization'))
  if (!authResult.ok) {
    void logAudit({
      tokenId: null,
      userId: null,
