  // 2. Rate limiting
  const rlResult = await checkRateLimit(authResult.tokenId, authResult.role)
  if (!rlResult.ok) {
    return NextResponse.json(
      {
        jsonrpc: '2.0',
        id: null,
        error: {
          code: MCP_ERROR.RATE_LIMIT,
          message: 'Rate limit exceeded',
          data: { retryAfter: rlResult.retryAfter },
        },
      },
      {
        status: 429,
        headers: { 'Retry-After': String(rlResult.retryAfter) },
      },
    )
  }

  // 3. Parse request body
  let body: unknown
  try {
    body = await req.json()
  } catch {
    return NextResponse.json(
      {
        jsonrpc: '2.0',
        id: null,
        error: { code: MCP_ERROR.PARSE_ERROR, message: 'Parse error' },
      },
      { status: 400 },
    )
  }

  // 4. Audit log (fire-and-forget)
  const rpcBody = body as {
    method?: string
    params?: { name?: string; arguments?: unknown }
    id?: unknown
  }
  const toolName = rpcBody?.params?.name ?? rpcBody?.method ?? 'unknown'
  void logAudit({
    tokenId: authResult.tokenId,
    userId: authResult.userId,
    toolName: String(toolName),
    params: rpcBody?.params?.arguments ?? {},
    status: 'success',
    latencyMs: Date.now() - start,
  })

  // 5. Handle MCP request via SDK
  try {
    const server = createMcpServer(authResult)
    const { StreamableHTTPServerTransport } = await import(
      '@modelcontextprotocol/sdk/server/streamableHttp.js'
    )
    const transport = new StreamableHTTPServerTransport({
      sessionIdGenerator: undefined,
    })
    await server.connect(transport)
    const response = await transport.handleRequest(req, new Response())
    return response
  } catch (err) {
    console.error('[mcp-route] internal error:', err)
    return NextResponse.json(
      {
        jsonrpc: '2.0',
        id: (rpcBody as any)?.id ?? null,
