import { describe, it, expect } from 'vitest'
import { searchTerm } from '../search-term'
import { prismaMock } from '@/vitest.setup'

const mockWord = (id: number, wordKor: string, wordEng: string, wordAbbr: string | null = null) => ({
  id,
  wordKor,
  wordEng,
  wordAbbr,
  domainId: null,
  createdAt: new Date(),
  updatedAt: new Date(),
})

describe('searchTerm', () => {
  it('queries word table and returns matching results', async () => {
    prismaMock.word.findMany.mockResolvedValue([mockWord(1, '사용자', 'USER', 'USR')])
    prismaMock.domain.findMany.mockResolvedValue([])
    prismaMock.forbiddenWord.findMany.mockResolvedValue([])

    const result = await searchTerm({ query: '사용자' })
    expect(result.results).toHaveLength(1)
    expect(result.results[0].type).toBe('word')
    expect(result.results[0].name).toBe('사용자')
    expect(result.results[0].abbr).toBe('USR')
  })

  it('returns empty results when no match', async () => {
    prismaMock.word.findMany.mockResolvedValue([])
    prismaMock.domain.findMany.mockResolvedValue([])
    prismaMock.forbiddenWord.findMany.mockResolvedValue([])

    const result = await searchTerm({ query: '없는단어xyz' })
    expect(result.results).toHaveLength(0)
    expect(result.total).toBe(0)
  })

  it('throws ZodError on empty query string', async () => {
    await expect(searchTerm({ query: '' })).rejects.toThrow()
  })

  it('queries only word table when type=word', async () => {
    prismaMock.word.findMany.mockResolvedValue([mockWord(2, '테스트', 'TEST')])

    const result = await searchTerm({ query: '테스트', type: 'word' })
    expect(prismaMock.domain.findMany).not.toHaveBeenCalled()
    expect(prismaMock.forbiddenWord.findMany).not.toHaveBeenCalled()
    expect(result.results[0].type).toBe('word')
  })

  it('respects limit and slices results to requested count', async () => {
    const words = Array.from({ length: 10 }, (_, i) =>
      mockWord(i + 1, `단어${i}`, `WORD${i}`),
    )
    prismaMock.word.findMany.mockResolvedValue(words)
    prismaMock.domain.findMany.mockResolvedValue([])
    prismaMock.forbiddenWord.findMany.mockResolvedValue([])

    const result = await searchTerm({ query: '단어', limit: 3 })
    expect(result.results.length).toBeLessThanOrEqual(3)
  })
})

