import { describe, it, expect } from 'vitest'
import { checkForbiddenInText } from '../check-forbidden'
import { prismaMock } from '@/vitest.setup'

describe('checkForbiddenInText', () => {
  it('detects forbidden word in text and returns position', async () => {
    prismaMock.forbiddenWord.findMany.mockResolvedValue([
      { id: 1, wordKor: '불법', reason: '법적 금지 용어', createdAt: new Date(), updatedAt: new Date() },
    ] as any)

    const result = await checkForbiddenInText({ text: '이것은 불법 행위입니다' })
    expect(result.hasForbidden).toBe(true)
    expect(result.matches).toHaveLength(1)
    expect(result.matches[0].word).toBe('불법')
    expect(result.matches[0].position).toBeGreaterThanOrEqual(0)
  })

  it('returns hasForbidden=false when no forbidden words in text', async () => {
    prismaMock.forbiddenWord.findMany.mockResolvedValue([
      { id: 1, wordKor: '불법', reason: null, createdAt: new Date(), updatedAt: new Date() },
    ] as any)

    const result = await checkForbiddenInText({ text: '정상적인 텍스트입니다' })
    expect(result.hasForbidden).toBe(false)
    expect(result.matches).toHaveLength(0)
  })

  it('detects multiple forbidden words in same text', async () => {
    prismaMock.forbiddenWord.findMany.mockResolvedValue([
      { id: 1, wordKor: '불법', reason: null, createdAt: new Date(), updatedAt: new Date() },
      { id: 2, wordKor: '도박', reason: '사행성', createdAt: new Date(), updatedAt: new Date() },
    ] as any)

    const result = await checkForbiddenInText({ text: '불법 도박은 금지됩니다' })
    expect(result.hasForbidden).toBe(true)
    expect(result.matches).toHaveLength(2)
  })

  it('throws ZodError on empty text', async () => {
    await expect(checkForbiddenInText({ text: '' })).rejects.toThrow()
  })
})

