import { describe, it, expect } from 'vitest'
import { validateIdentifier } from '../validate-identifier'
import { prismaMock } from '@/vitest.setup'

const mockStdWord = (abbr: string) => ({
  id: 1, wordKor: '테스트', wordEng: 'TEST', wordAbbr: abbr,
  domainId: null, createdAt: new Date(), updatedAt: new Date(),
})

describe('validateIdentifier', () => {
  it('returns valid=true when all DB tokens match standard words', async () => {
    // USER_NM → tokens: ['USER', 'NM']
    prismaMock.word.findFirst
      .mockResolvedValueOnce(mockStdWord('USER') as any)
      .mockResolvedValueOnce(mockStdWord('NM') as any)

    const result = await validateIdentifier({ name: 'USER_NM', kind: 'db_column' })
    expect(result.valid).toBe(true)
    expect(result.invalidTokens).toHaveLength(0)
    expect(result.tokens).toHaveLength(2)
  })

  it('returns valid=true when token matches custom word (not standard)', async () => {
    // BLKCHAIN → not in standard, but in custom
    prismaMock.word.findFirst.mockResolvedValue(null)
    prismaMock.tbTrmCustomWord.findFirst.mockResolvedValue({
      id: 1n, wordKrNm: '블록체인', wordEngNm: 'BLOCKCHAIN', wordEngAbbrNm: 'BLKCHAIN',
      useYn: 'Y', reasonCn: null, rgtrId: null, regDt: new Date(), mdfrId: null, mdfcnDt: null,
    } as any)

    const result = await validateIdentifier({ name: 'BLKCHAIN_ID', kind: 'db_column' })
    expect(result.valid).toBe(true)
  })

  it('returns valid=false with suggestionMessage for unknown tokens', async () => {
    prismaMock.word.findFirst.mockResolvedValue(null)
    prismaMock.tbTrmCustomWord.findFirst.mockResolvedValue(null)

    const result = await validateIdentifier({ name: 'UNKNWN_COL', kind: 'db_column' })
    expect(result.valid).toBe(false)
    expect(result.invalidTokens.length).toBeGreaterThan(0)
    expect(result.suggestionMessage).toMatch(/비표준 토큰/)
  })

  it('correctly tokenizes DB column USER_NM into [USER, NM]', async () => {
    prismaMock.word.findFirst.mockResolvedValue(mockStdWord('USER') as any)
    prismaMock.word.findFirst.mockResolvedValueOnce(mockStdWord('USER') as any)
    prismaMock.word.findFirst.mockResolvedValueOnce(mockStdWord('NM') as any)

    const result = await validateIdentifier({ name: 'USER_NM', kind: 'db_column' })
    expect(result.tokens.map((t) => t.token)).toEqual(['USER', 'NM'])
  })

  it('correctly tokenizes Java field userName into [USER, NAME]', async () => {
    prismaMock.word.findFirst
      .mockResolvedValueOnce(mockStdWord('USER') as any)
      .mockResolvedValueOnce(mockStdWord('NAME') as any)

    const result = await validateIdentifier({ name: 'userName', kind: 'java_field' })
    // camelCase split: u + ser → USER, N + ame → NAME
    expect(result.tokens.every((t) => ['USER', 'NAME', 'USERN', 'AME'].includes(t.token))).toBe(true)
  })
})

