    const res = await POST(makeRequest(
      { jsonrpc: '2.0', id: 1, method: 'initialize', params: { protocolVersion: '2025-03-26', capabilities: {} } },
      `Bearer ${VALID_TOKEN}`,
    ) as any)
    expect(res.status).toBe(200)
  })

  it('8. tools/list 요청 → HTTP 200', async () => {
    prismaMock.tbTrmMcpToken.findUnique.mockResolvedValue(mockActiveToken as any)
    const res = await POST(makeRequest(
      { jsonrpc: '2.0', id: 2, method: 'tools/list' },
      `Bearer ${VALID_TOKEN}`,
    ) as any)
    expect(res.status).toBe(200)
  })

  it('9. search_term (USER) → HTTP 200', async () => {
    prismaMock.tbTrmMcpToken.findUnique.mockResolvedValue(mockActiveToken as any)
    prismaMock.word.findMany.mockResolvedValue([])
    prismaMock.domain.findMany.mockResolvedValue([])
    prismaMock.forbiddenWord.findMany.mockResolvedValue([])
    const res = await POST(makeRequest(
      { jsonrpc: '2.0', id: 3, method: 'tools/call', params: { name: 'search_term', arguments: { query: '사용자' } } },
      `Bearer ${VALID_TOKEN}`,
    ) as any)
    expect(res.status).toBe(200)
  })

  it('10. register_custom_word (USER) → isError or permission denied response', async () => {
    prismaMock.tbTrmMcpToken.findUnique.mockResolvedValue(mockActiveToken as any)
    const res = await POST(makeRequest(
      { jsonrpc: '2.0', id: 4, method: 'tools/call', params: { name: 'register_custom_word', arguments: { koreanName: '테스트' } } },
      `Bearer ${VALID_TOKEN}`,
    ) as any)
    // Route returns 200 (MCP layer handles permission internally via isError)
    expect([200, 403]).toContain(res.status)
  })

  it('11. 감사 로그가 성공 요청에 기록됨', async () => {
    prismaMock.tbTrmMcpToken.findUnique.mockResolvedValue(mockActiveToken as any)
    await POST(makeRequest(
      { jsonrpc: '2.0', id: 5, method: 'tools/list' },
