    expect(prismaMock.tbTrmMcpAuditLog.create).toHaveBeenCalled()
  })

  it('12. 감사 로그가 인증 실패 요청에도 기록됨 (denied)', async () => {
    prismaMock.tbTrmMcpToken.findUnique.mockResolvedValue(null)
