  // 5. Handle MCP request via SDK
  try {
    const server = createMcpServer(authResult)
    const { StreamableHTTPServerTransport } = await import(
      '@modelcontextprotocol/sdk/server/streamableHttp.js'
    )
    const transport = new StreamableHTTPServerTransport({
      sessionIdGenerator: undefined,
    })
    await server.connect(transport)
    const response = await transport.handleRequest(req, new Response())
    return response
  } catch (err) {
    console.error('[mcp-route] internal error:', err)
    return NextResponse.json(
      {
        jsonrpc: '2.0',
        id: (rpcBody as any)?.id ?? null,
        error: { code: MCP_ERROR.INTERNAL_ERROR, message: 'Internal server error' },
      },
      { status: 500 },
    )
  }
}

