import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js'
import { z } from 'zod'
import type { AuthContext } from '../errors'
import { MCP_ERROR } from '../errors'
import { searchTerm, searchTermSchema } from './search-term'
import { getWordDetail } from './get-word-detail'
import { checkForbiddenInText, checkForbiddenSchema } from './check-forbidden'
import { validateIdentifier, validateIdentifierSchema } from './validate-identifier'
import { suggestNaming, suggestNamingSchema } from './suggest-naming'

// get_word_detail accepts abbr OR id — use a combined optional schema
const getWordDetailInputSchema = z.object({
  abbr: z.string().optional(),
  id: z.number().int().positive().optional(),
})

const registerCustomWordSchema = z.object({
  koreanName: z.string().min(1),
  englishName: z.string().optional(),
  englishAbbr: z.string().optional(),
  reason: z.string().optional(),
})

export function createMcpServer(auth: AuthContext) {
  const server = new McpServer({
    name: 'trmdict',
    version: '1.0.0',
  })

  // Tool 1: search_term
  server.tool(
    'search_term',
    '행안부 표준 단어/도메인/금칙어를 통합 검색합니다.',
    searchTermSchema.shape,
    async (args) => {
      const result = await searchTerm(args)
      return { content: [{ type: 'text' as const, text: JSON.stringify(result) }] }
    },
  )

  // Tool 2: get_word_detail
  server.tool(
    'get_word_detail',
    '약어(abbr) 또는 ID로 표준 단어 상세 정보를 조회합니다.',
    getWordDetailInputSchema.shape,
    async (args) => {
      const result = await getWordDetail(args)
      return { content: [{ type: 'text' as const, text: JSON.stringify(result) }] }
    },
  )

  // Tool 3: check_forbidden_in_text
  server.tool(
    'check_forbidden_in_text',
    '텍스트에서 금칙어 포함 여부를 스캔합니다.',
    checkForbiddenSchema.shape,
    async (args) => {
      const result = await checkForbiddenInText(args)
      return { content: [{ type: 'text' as const, text: JSON.stringify(result) }] }
    },
  )

  // Tool 4: validate_identifier
  server.tool(
    'validate_identifier',
    'DB 컬럼/테이블 또는 Java 식별자가 표준 단어 기반인지 검증합니다.',
    validateIdentifierSchema.shape,
    async (args) => {
      const result = await validateIdentifier(args)
      return { content: [{ type: 'text' as const, text: JSON.stringify(result) }] }
    },
  )

  // Tool 5: suggest_naming
  server.tool(
    'suggest_naming',
    '한글 설명에서 표준 단어를 매핑하여 DB 컬럼명/Java 필드명을 제안합니다.',
    suggestNamingSchema.shape,
    async (args) => {
      const result = await suggestNaming(args)
      return { content: [{ type: 'text' as const, text: JSON.stringify(result) }] }
    },
  )

  // register_custom_word: ADMIN only (Phase 2 stub — permission check only)
  server.tool(
    'register_custom_word',
    '비표준 용어를 커스텀 단어 목록에 등록합니다. (ADMIN 전용)',
    registerCustomWordSchema.shape,
    async (_args) => {
      if (auth.role !== 'ADMIN') {
        return {
          content: [{ type: 'text' as const, text: JSON.stringify({ error: 'Permission denied', code: MCP_ERROR.PERMISSION_DENIED }) }],
          isError: true,
        }
      }
      return {
        content: [{ type: 'text' as const, text: JSON.stringify({ status: 'not_implemented', message: 'Phase 2에서 구현 예정' }) }],
        isError: true,
      }
    },
  )

  return server
}

